steps.command:
SELECT table_name, privilege_type
FROM information_schema.table_privileges
WHERE grantee = 'app_user' AND table_name = 'ticket_flights';

SELECT *
FROM pg_stat_activity
WHERE datname = 'demo' AND state = 'active' AND query LIKE '%flights%';

SELECT relname AS table_name, pg_size_pretty(pg_total_relation_size(relid)) AS total_size
FROM pg_catalog.pg_statio_user_tables
ORDER BY pg_total_relation_size(relid) DESC;

SELECT indexname, pg_size_pretty(indexsize) AS size
FROM pg_indexes
WHERE tablename = 'ticket_flights';

SELECT indexname, pg_size_pretty(pg_relation_size(indexrelid)) AS size
FROM pg_indexes
WHERE tablename = 'ticket_flights';

SELECT indexname, pg_size_pretty(pg_total_relation_size(indexrelid)) AS size
FROM pg_indexes
WHERE tablename = 'ticket_flights';

SELECT indexname, pg_size_pretty(pg_indexes_size(indexrelid)) AS size
FROM pg_indexes
WHERE tablename = 'ticket_flights';

SELECT indexname, pg_size_pretty(pg_relation_size(indexrelid)) AS size
FROM pg_indexes
WHERE tablename = 'ticket_flights';

SELECT indexname, pg_size_pretty(pg_total_relation_size(indexrelid)) AS size
FROM pg_stat_user_indexes
WHERE relname = 'ticket_flights';

SELECT indexrelname AS indexname, pg_size_pretty(pg_total_relation_size(indexrelid)) AS size
FROM pg_stat_user_indexes
WHERE relname = 'ticket_flights';
